use crate::ast_types::{BridgeExpression, BridgeNodePlan, BridgeOperation};

pub trait PolyglotEmitter {
    fn emit(&self, operations: &[BridgeOperation], source_language: &str) -> String;
}

pub struct PythonEmitter;
pub struct RustEmitter;
pub struct GoEmitter;
pub struct FortranEmitter;
pub struct FrankieEmitter;
pub struct ForrestEmitter;
pub struct LeanEmitter;
pub struct GenericEmitter {
    pub target_language: String,
}

fn extract_ghost_source<'a>(ghost_mass: &'a Option<serde_json::Value>) -> Option<&'a str> {
    if let Some(gm) = ghost_mass {
        if let Some(source) = gm.get("source") {
            return source.as_str();
        }
    }
    None
}

impl PolyglotEmitter for PythonEmitter {
    fn emit(&self, operations: &[BridgeOperation], source_language: &str) -> String {
        let mut out = String::new();
        let is_same_lang = source_language == "python" || source_language == "py";
        // Python runs async natively with asyncio
        for op in operations {
            if is_same_lang {
                let ghost_mass = match op {
                    BridgeOperation::Assign { plan: BridgeNodePlan::Assign { ghost_mass, .. } } => ghost_mass,
                    BridgeOperation::Call { plan: BridgeNodePlan::Call { ghost_mass, .. } } => ghost_mass,
                    BridgeOperation::Return { plan: BridgeNodePlan::Return { ghost_mass, .. } } => ghost_mass,
                    _ => &None,
                };
                if let Some(s) = extract_ghost_source(ghost_mass) {
                    out.push_str(s);
                    out.push('\n');
                    continue;
                }
            }
            match op {
                BridgeOperation::Assign { plan } => {
                    if let BridgeNodePlan::Assign { binding_name, expression, .. } = plan {
                        out.push_str(&format!("{} = {}\n", binding_name, emit_expr_py(expression, source_language)));
                    }
                }
                BridgeOperation::Call { plan } => {
                    if let BridgeNodePlan::Call { callee, args, assign_to, this_arg, .. } = plan {
                        let mut call_str = String::new();
                        if let Some(target) = assign_to {
                            call_str.push_str(&format!("{} = ", target));
                        }
                        
                        let args_str: Vec<String> = args.iter().map(|a| emit_expr_py(a, source_language)).collect();
                        
                        if let Some(this) = this_arg {
                            let callee_text = if let BridgeExpression::Member { property, .. } = callee {
                                property.clone()
                            } else {
                                emit_expr_py(callee, source_language)
                            };
                            call_str.push_str(&format!("{}.{}({})", emit_expr_py(this, source_language), callee_text, args_str.join(", ")));
                        } else {
                            // Default to await for side effect calls
                            call_str.push_str(&format!("await {}({})", emit_expr_py(callee, source_language), args_str.join(", ")));
                        }
                        out.push_str(&call_str);
                        out.push('\n');
                    }
                }
                BridgeOperation::Return { plan } => {
                    if let BridgeNodePlan::Return { expression, .. } = plan {
                        out.push_str(&format!("return {}\n", emit_expr_py(expression, source_language)));
                    }
                }
                BridgeOperation::Parallel { branches, .. } => {
                    let mut b_out = String::new();
                    let mut awaitables = Vec::new();
                    let mut assigns = Vec::new();
                    for branch in branches {
                        if let BridgeNodePlan::Call { callee, args, assign_to, .. } = branch {
                            let args_str: Vec<String> = args.iter().map(|a| emit_expr_py(a, source_language)).collect();
                            awaitables.push(format!("{}({})", emit_expr_py(callee, source_language), args_str.join(", ")));
                            if let Some(target) = assign_to {
                                assigns.push(target.clone());
                            } else {
                                assigns.push("_".to_string());
                            }
                        }
                    }
                    if assigns.len() > 0 {
                        b_out.push_str(&format!("{} = await asyncio.gather({})\n", assigns.join(", "), awaitables.join(", ")));
                    } else {
                        b_out.push_str(&format!("await asyncio.gather({})\n", awaitables.join(", ")));
                    }
                    out.push_str(&b_out);
                }
            }
        }
        out
    }
}

fn emit_expr_py(expr: &BridgeExpression, source_language: &str) -> String {
    if source_language == "python" || source_language == "py" {
        let ghost_mass = match expr {
            BridgeExpression::Literal { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Binding { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Runtime { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Input { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Member { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Index { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Array { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Object { ghost_mass, .. } => ghost_mass,
        };
        if let Some(s) = extract_ghost_source(ghost_mass) {
            return s.to_string();
        }
    }
    match expr {
        BridgeExpression::Literal { value, .. } => {
            if value.is_null() {
                "None".to_string()
            } else if value.is_boolean() {
                if value.as_bool().unwrap() { "True".to_string() } else { "False".to_string() }
            } else {
                value.to_string()
            }
        }
        BridgeExpression::Binding { name, .. } | BridgeExpression::Runtime { name, .. } => {
            name.clone()
        }
        BridgeExpression::Input { .. } => "input_arg".to_string(),
        BridgeExpression::Member { target, property, .. } => {
            format!("{}.{}", emit_expr_py(target, source_language), property)
        }
        BridgeExpression::Index { target, index, .. } => {
            format!("{}[{}]", emit_expr_py(target, source_language), index)
        }
        BridgeExpression::Array { items, .. } => {
            let items_str: Vec<String> = items.iter().map(|i| emit_expr_py(i, source_language)).collect();
            format!("[{}]", items_str.join(", "))
        }
        BridgeExpression::Object { entries, .. } => {
            let mut entries_str = Vec::new();
            for e in entries {
                entries_str.push(format!("'{}': {}", e.key, emit_expr_py(&e.value, source_language)));
            }
            format!("{{{}}}", entries_str.join(", "))
        }
    }
}

impl PolyglotEmitter for RustEmitter {
    fn emit(&self, operations: &[BridgeOperation], source_language: &str) -> String {
        let mut out = String::new();
        let is_same_lang = source_language == "rust" || source_language == "rs";
        // Rust runs natively with tokio
        for op in operations {
            if is_same_lang {
                let ghost_mass = match op {
                    BridgeOperation::Assign { plan: BridgeNodePlan::Assign { ghost_mass, .. } } => ghost_mass,
                    BridgeOperation::Call { plan: BridgeNodePlan::Call { ghost_mass, .. } } => ghost_mass,
                    BridgeOperation::Return { plan: BridgeNodePlan::Return { ghost_mass, .. } } => ghost_mass,
                    _ => &None,
                };
                if let Some(s) = extract_ghost_source(ghost_mass) {
                    out.push_str(s);
                    out.push('\n');
                    continue;
                }
            }
            match op {
                BridgeOperation::Assign { plan } => {
                    if let BridgeNodePlan::Assign { binding_name, expression, .. } = plan {
                        out.push_str(&format!("let {} = {};\n", binding_name, emit_expr_rs(expression, source_language)));
                    }
                }
                BridgeOperation::Call { plan } => {
                    if let BridgeNodePlan::Call { callee, args, assign_to, this_arg, .. } = plan {
                        let mut call_str = String::new();
                        if let Some(target) = assign_to {
                            call_str.push_str(&format!("let {} = ", target));
                        }
                        
                        let args_str: Vec<String> = args.iter().map(|a| emit_expr_rs(a, source_language)).collect();
                        
                        if let Some(this) = this_arg {
                            let (is_frf, callee_text) = if let BridgeExpression::Member { property, .. } = callee {
                                let r = match property.as_str() {
                                    "map" | "filter" | "forEach" => true,
                                    _ => false,
                                };
                                (r, property.clone())
                            } else {
                                (false, emit_expr_rs(callee, source_language))
                            };
                            
                            if is_frf {
                                match callee_text.as_str() {
                                    "map" => {
                                        call_str.push_str(&format!("{}.into_par_iter().map({}).with_sub_chunks_auto().collect::<Vec<_>>();", emit_expr_rs(this, source_language), args_str.join(", ")));
                                    }
                                    "filter" => {
                                        call_str.push_str(&format!("{}.into_par_iter().filter({}).with_sub_chunks_auto().collect::<Vec<_>>();", emit_expr_rs(this, source_language), args_str.join(", ")));
                                    }
                                    "forEach" => {
                                        call_str.push_str(&format!("{}.par_iter().with_sub_chunks_auto().for_each({});", emit_expr_rs(this, source_language), args_str.join(", ")));
                                    }
                                    _ => unreachable!(),
                                }
                            } else {
                                call_str.push_str(&format!("{}.{}({}).await;", emit_expr_rs(this, source_language), callee_text, args_str.join(", ")));
                            }
                        } else {
                            call_str.push_str(&format!("{}({}).await;", emit_expr_rs(callee, source_language), args_str.join(", ")));
                        }
                        out.push_str(&call_str);
                        out.push('\n');
                    }
                }
                BridgeOperation::Return { plan } => {
                    if let BridgeNodePlan::Return { expression, .. } = plan {
                        let expr_str = emit_expr_rs(expression, source_language);
                        if expr_str == "()" {
                            out.push_str("return;\n");
                        } else {
                            out.push_str(&format!("return {};\n", expr_str));
                        }
                    }
                }
                BridgeOperation::Parallel { branches, .. } => {
                    let mut b_out = String::new();
                    let mut awaits = Vec::new();
                    let mut assigns = Vec::new();
                    for branch in branches {
                        if let BridgeNodePlan::Call { callee, args, assign_to, .. } = branch {
                            let args_str: Vec<String> = args.iter().map(|a| emit_expr_rs(a, source_language)).collect();
                            awaits.push(format!("{}({})", emit_expr_rs(callee, source_language), args_str.join(", ")));
                            if let Some(target) = assign_to {
                                assigns.push(target.clone());
                            } else {
                                assigns.push("_".to_string());
                            }
                        }
                    }
                    if assigns.len() > 0 {
                        b_out.push_str(&format!("let ({}) = tokio::join!({});\n", assigns.join(", "), awaits.join(", ")));
                    } else {
                        b_out.push_str(&format!("tokio::join!({});\n", awaits.join(", ")));
                    }
                    out.push_str(&b_out);
                }
            }
        }
        out
    }
}

fn emit_expr_rs(expr: &BridgeExpression, source_language: &str) -> String {
    if source_language == "rust" || source_language == "rs" {
        let ghost_mass = match expr {
            BridgeExpression::Literal { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Binding { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Runtime { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Input { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Member { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Index { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Array { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Object { ghost_mass, .. } => ghost_mass,
        };
        if let Some(s) = extract_ghost_source(ghost_mass) {
            return s.to_string();
        }
    }
    match expr {
        BridgeExpression::Literal { value, .. } => {
            if value.is_null() {
                "()".to_string()
            } else if value.is_boolean() {
                if value.as_bool().unwrap() { "true".to_string() } else { "false".to_string() }
            } else if value.is_string() {
                format!("\"{}\".to_string()", value.as_str().unwrap())
            } else {
                value.to_string()
            }
        }
        BridgeExpression::Binding { name, .. } | BridgeExpression::Runtime { name, .. } => {
            name.clone()
        }
        BridgeExpression::Input { .. } => "input_arg".to_string(),
        BridgeExpression::Member { target, property, .. } => {
            format!("{}.{}", emit_expr_rs(target, source_language), property)
        }
        BridgeExpression::Index { target, index, .. } => {
            format!("{}[{}]", emit_expr_rs(target, source_language), index)
        }
        BridgeExpression::Array { items, .. } => {
            let items_str: Vec<String> = items.iter().map(|i| emit_expr_rs(i, source_language)).collect();
            format!("vec![{}]", items_str.join(", "))
        }
        BridgeExpression::Object { .. } => {
            // Rust objects are hard to map generically without structs, fall back to json macro
            "serde_json::json!({})".to_string()
        }
    }
}

impl PolyglotEmitter for GoEmitter {
    fn emit(&self, operations: &[BridgeOperation], source_language: &str) -> String {
        let mut out = String::new();
        let is_same_lang = source_language == "go";
        for op in operations {
            if is_same_lang {
                let ghost_mass = match op {
                    BridgeOperation::Assign { plan: BridgeNodePlan::Assign { ghost_mass, .. } } => ghost_mass,
                    BridgeOperation::Call { plan: BridgeNodePlan::Call { ghost_mass, .. } } => ghost_mass,
                    BridgeOperation::Return { plan: BridgeNodePlan::Return { ghost_mass, .. } } => ghost_mass,
                    _ => &None,
                };
                if let Some(s) = extract_ghost_source(ghost_mass) {
                    out.push_str(s);
                    out.push('\n');
                    continue;
                }
            }
            match op {
                BridgeOperation::Assign { plan } => {
                    if let BridgeNodePlan::Assign { binding_name, expression, .. } = plan {
                        out.push_str(&format!("{} := {}\n", binding_name, emit_expr_go(expression, source_language)));
                    }
                }
                BridgeOperation::Call { plan } => {
                    if let BridgeNodePlan::Call { callee, args, assign_to, this_arg, .. } = plan {
                        let mut call_str = String::new();
                        if let Some(target) = assign_to {
                            call_str.push_str(&format!("{} := ", target));
                        }
                        
                        let args_str: Vec<String> = args.iter().map(|a| emit_expr_go(a, source_language)).collect();
                        
                        if let Some(this) = this_arg {
                            let callee_text = if let BridgeExpression::Member { property, .. } = callee {
                                property.clone()
                            } else {
                                emit_expr_go(callee, source_language)
                            };
                            call_str.push_str(&format!("{}.{}({})", emit_expr_go(this, source_language), callee_text, args_str.join(", ")));
                        } else {
                            call_str.push_str(&format!("{}({})", emit_expr_go(callee, source_language), args_str.join(", ")));
                        }
                        out.push_str(&call_str);
                        out.push('\n');
                    }
                }
                BridgeOperation::Return { plan } => {
                    if let BridgeNodePlan::Return { expression, .. } = plan {
                        let expr_str = emit_expr_go(expression, source_language);
                        if expr_str == "nil" {
                            out.push_str("return\n");
                        } else {
                            out.push_str(&format!("return {}\n", expr_str));
                        }
                    }
                }
                BridgeOperation::Parallel { branches, .. } => {
                    let mut b_out = String::new();
                    b_out.push_str(&format!("var wg sync.WaitGroup\nwg.Add({})\n", branches.len()));
                    
                    for (_i, branch) in branches.iter().enumerate() {
                        if let BridgeNodePlan::Call { callee, args, assign_to, .. } = branch {
                            if let Some(target) = assign_to {
                                b_out.push_str(&format!("var {} interface{{}}\n", target));
                            }
                            let args_str: Vec<String> = args.iter().map(|a| emit_expr_go(a, source_language)).collect();
                            b_out.push_str("go func() {\n\tdefer wg.Done()\n");
                            let call = format!("{}({})", emit_expr_go(callee, source_language), args_str.join(", "));
                            if let Some(target) = assign_to {
                                b_out.push_str(&format!("\t{} = {}\n", target, call));
                            } else {
                                b_out.push_str(&format!("\t{}\n", call));
                            }
                            b_out.push_str("}()\n");
                        }
                    }
                    b_out.push_str("wg.Wait()\n");
                    out.push_str(&b_out);
                }
            }
        }
        out
    }
}

fn emit_expr_go(expr: &BridgeExpression, source_language: &str) -> String {
    if source_language == "go" {
        let ghost_mass = match expr {
            BridgeExpression::Literal { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Binding { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Runtime { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Input { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Member { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Index { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Array { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Object { ghost_mass, .. } => ghost_mass,
        };
        if let Some(s) = extract_ghost_source(ghost_mass) {
            return s.to_string();
        }
    }
    match expr {
        BridgeExpression::Literal { value, .. } => {
            if value.is_null() {
                "nil".to_string()
            } else if value.is_boolean() {
                if value.as_bool().unwrap() { "true".to_string() } else { "false".to_string() }
            } else {
                value.to_string()
            }
        }
        BridgeExpression::Binding { name, .. } | BridgeExpression::Runtime { name, .. } => {
            name.clone()
        }
        BridgeExpression::Input { .. } => "inputArg".to_string(),
        BridgeExpression::Member { target, property, .. } => {
            format!("{}.{}", emit_expr_go(target, source_language), property)
        }
        BridgeExpression::Index { target, index, .. } => {
            format!("{}[{}]", emit_expr_go(target, source_language), index)
        }
        BridgeExpression::Array { items, .. } => {
            let items_str: Vec<String> = items.iter().map(|i| emit_expr_go(i, source_language)).collect();
            format!("[]interface{{}}{{{}}}", items_str.join(", "))
        }
        BridgeExpression::Object { entries, .. } => {
            let mut entries_str = Vec::new();
            for e in entries {
                entries_str.push(format!("\"{}\": {}", e.key, emit_expr_go(&e.value, source_language)));
            }
            format!("map[string]interface{{}}{{{}}}", entries_str.join(", "))
        }
    }
}

pub struct LanguageSyntaxDialect {
    pub lang_name: String,
    pub null_literal: &'static str,
    pub true_literal: &'static str,
    pub false_literal: &'static str,
    pub comment_prefix: &'static str,
    pub assignment_format: &'static str,
    pub return_format: &'static str,
    pub prop_accessor: &'static str,
    pub array_open: &'static str,
    pub array_close: &'static str,
    pub string_quote: &'static str,
    pub call_format: &'static str,
    pub method_call_format: &'static str,
}

impl Default for LanguageSyntaxDialect {
    fn default() -> Self {
        Self {
            lang_name: "unknown".to_string(),
            null_literal: "null",
            true_literal: "true",
            false_literal: "false",
            comment_prefix: "//",
            assignment_format: "{target} = {expr}",
            return_format: "return {expr}",
            prop_accessor: "{target}.{prop}",
            array_open: "[",
            array_close: "]",
            string_quote: "\"",
            call_format: "{callee}({args})",
            method_call_format: "{this}.{callee}({args})",
        }
    }
}

impl LanguageSyntaxDialect {
    pub fn for_language(lang: &str) -> Self {
        match lang {
            "c" | "cpp" | "java" | "csharp" => Self {
                lang_name: lang.to_string(),
                ..Default::default()
            },
            "lua" => Self {
                lang_name: "lua".to_string(),
                null_literal: "nil",
                comment_prefix: "--",
                method_call_format: "{this}:{callee}({args})",
                array_open: "{",
                array_close: "}",
                string_quote: "\'",
                ..Default::default()
            },
            "javascript" | "typescript" => Self {
                lang_name: lang.to_string(),
                assignment_format: "let {target} = {expr}",
                ..Default::default()
            },
            "ruby" => Self {
                lang_name: "ruby".to_string(),
                null_literal: "nil",
                comment_prefix: "#",
                return_format: "return {expr}",
                ..Default::default()
            },
            "swift" => Self {
                lang_name: "swift".to_string(),
                null_literal: "nil",
                assignment_format: "let {target} = {expr}",
                ..Default::default()
            },
            "haskell" | "ocaml" | "fsharp" | "elixir" | "lean" => Self {
                lang_name: lang.to_string(),
                assignment_format: "let {target} = {expr} in",
                return_format: "{expr}",
                null_literal: "Nothing",
                true_literal: "True",
                false_literal: "False",
                comment_prefix: "--",
                call_format: "{callee} {args}",
                method_call_format: "{callee} {this} {args}",
                ..Default::default()
            },
            "php" => Self {
                lang_name: "php".to_string(),
                prop_accessor: "{target}->{prop}",
                method_call_format: "{this}->{callee}({args})",
                ..Default::default()
            },
            "kotlin" => Self {
                lang_name: "kotlin".to_string(),
                assignment_format: "val {target} = {expr}",
                ..Default::default()
            },
            "zig" => Self {
                lang_name: "zig".to_string(),
                assignment_format: "const {target} = {expr}",
                array_open: ".{",
                array_close: "}",
                ..Default::default()
            },
            _ => Default::default(),
        }
    }
}

impl PolyglotEmitter for GenericEmitter {
    fn emit(&self, operations: &[BridgeOperation], source_language: &str) -> String {
        let mut out = String::new();
        let dialect = LanguageSyntaxDialect::for_language(&self.target_language);
        
        for op in operations {
            if source_language == self.target_language {
                let ghost_mass = match op {
                    BridgeOperation::Assign { plan: BridgeNodePlan::Assign { ghost_mass, .. } } => ghost_mass,
                    BridgeOperation::Call { plan: BridgeNodePlan::Call { ghost_mass, .. } } => ghost_mass,
                    BridgeOperation::Return { plan: BridgeNodePlan::Return { ghost_mass, .. } } => ghost_mass,
                    _ => &None,
                };
                if let Some(s) = extract_ghost_source(ghost_mass) {
                    out.push_str(s);
                    out.push('\n');
                    continue;
                }
            }
            match op {
                BridgeOperation::Assign { plan } => {
                    if let BridgeNodePlan::Assign { binding_name, expression, .. } = plan {
                        out.push_str(&format!("{}\n", dialect.assignment_format.replace("{target}", binding_name).replace("{expr}", &emit_expr_generic(expression, &dialect))));
                    }
                }
                BridgeOperation::Call { plan } => {
                    if let BridgeNodePlan::Call { callee, args, assign_to, this_arg, .. } = plan {
                        let args_str: Vec<String> = args.iter().map(|a| emit_expr_generic(a, &dialect)).collect();
                        let joined_args = args_str.join(", ");
                        
                        let callee_text = if let BridgeExpression::Member { property, .. } = callee {
                            property.clone()
                        } else {
                            emit_expr_generic(callee, &dialect)
                        };
                        
                        let mut call_str = if let Some(this) = this_arg {
                            dialect.method_call_format.replace("{this}", &emit_expr_generic(this, &dialect)).replace("{callee}", &callee_text).replace("{args}", &joined_args)
                        } else {
                            dialect.call_format.replace("{callee}", &emit_expr_generic(callee, &dialect)).replace("{args}", &joined_args)
                        };
                        
                        if let Some(target) = assign_to {
                            call_str = dialect.assignment_format.replace("{target}", target).replace("{expr}", &call_str);
                        }
                        out.push_str(&format!("{}\n", call_str));
                    }
                }
                BridgeOperation::Return { plan } => {
                    if let BridgeNodePlan::Return { expression, .. } = plan {
                        let expr_str = emit_expr_generic(expression, &dialect);
                        if expr_str == dialect.null_literal {
                            out.push_str(&format!("{}\n", dialect.return_format.replace(" {expr}", "")));
                        } else {
                            out.push_str(&format!("{}\n", dialect.return_format.replace("{expr}", &expr_str)));
                        }
                    }
                }
                BridgeOperation::Parallel { branches, .. } => {
                    out.push_str(&format!("{} PARALLEL-EXEC BEGIN\n", dialect.comment_prefix));
                    for branch in branches {
                        if let BridgeNodePlan::Call { callee, args, assign_to, .. } = branch {
                            let args_str: Vec<String> = args.iter().map(|a| emit_expr_generic(a, &dialect)).collect();
                            let joined_args = args_str.join(", ");
                            let mut call_str = dialect.call_format.replace("{callee}", &emit_expr_generic(callee, &dialect)).replace("{args}", &joined_args);
                            if let Some(target) = assign_to {
                                call_str = dialect.assignment_format.replace("{target}", target).replace("{expr}", &call_str);
                            }
                            out.push_str(&format!("{}\n", call_str));
                        }
                    }
                    out.push_str(&format!("{} PARALLEL-EXEC END\n", dialect.comment_prefix));
                }
            }
        }
        out
    }
}

fn emit_expr_generic(expr: &BridgeExpression, dialect: &LanguageSyntaxDialect) -> String {
    let ghost_mass = match expr {
        BridgeExpression::Literal { ghost_mass, .. } => ghost_mass,
        BridgeExpression::Binding { ghost_mass, .. } => ghost_mass,
        BridgeExpression::Runtime { ghost_mass, .. } => ghost_mass,
        BridgeExpression::Input { ghost_mass, .. } => ghost_mass,
        BridgeExpression::Member { ghost_mass, .. } => ghost_mass,
        BridgeExpression::Index { ghost_mass, .. } => ghost_mass,
        BridgeExpression::Array { ghost_mass, .. } => ghost_mass,
        BridgeExpression::Object { ghost_mass, .. } => ghost_mass,
    };
    if let Some(s) = extract_ghost_source(ghost_mass) {
        return s.to_string();
    }
    
    match expr {
        BridgeExpression::Literal { value, .. } => {
            if value.is_null() {
                dialect.null_literal.to_string()
            } else if value.is_boolean() {
                if value.as_bool().unwrap() { dialect.true_literal.to_string() } else { dialect.false_literal.to_string() }
            } else if value.is_string() {
                format!("{}{}{}", dialect.string_quote, value.as_str().unwrap(), dialect.string_quote)
            } else {
                value.to_string()
            }
        }
        BridgeExpression::Binding { name, .. } | BridgeExpression::Runtime { name, .. } => {
            name.clone()
        }
        BridgeExpression::Input { .. } => "input_arg".to_string(),
        BridgeExpression::Member { target, property, .. } => {
            dialect.prop_accessor.replace("{target}", &emit_expr_generic(target, dialect)).replace("{prop}", property)
        }
        BridgeExpression::Index { target, index, .. } => {
            format!("{}[{}]", emit_expr_generic(target, dialect), index)
        }
        BridgeExpression::Array { items, .. } => {
            let items_str: Vec<String> = items.iter().map(|i| emit_expr_generic(i, dialect)).collect();
            format!("{}{}{}", dialect.array_open, items_str.join(", "), dialect.array_close)
        }
        BridgeExpression::Object { .. } => {
            format!("{} Object mapping not natively supported dynamically", dialect.comment_prefix)
        }
    }
}

pub struct GnotEmitter;

impl PolyglotEmitter for GnotEmitter {
    fn emit(&self, operations: &[BridgeOperation], source_language: &str) -> String {
        let mut out = String::new();
        out.push_str(&format!("using\n  {}\n\n", source_language));
        out.push_str("is polyglot_translation\n");

        for op in operations {
            match op {
                BridgeOperation::Assign { plan } => {
                    if let BridgeNodePlan::Assign { binding_name, expression, .. } = plan {
                        out.push_str(&format!("  {} <- {}, yield({})\n", binding_name, source_language, emit_gnot_callee_expr(expression)));
                    }
                }
                BridgeOperation::Call { plan } => {
                    if let BridgeNodePlan::Call { callee, args, assign_to, this_arg, .. } = plan {
                        let mut arg_parts = Vec::new();
                        for a in args {
                            arg_parts.push(emit_gnot_callee_expr(a));
                        }
                        
                        let callee_text_bare = if let BridgeExpression::Member { property, .. } = callee {
                            property.clone()
                        } else {
                            emit_gnot_callee_expr(callee)
                        };
                        
                        let callee_text = if let Some(this_val) = this_arg {
                             format!("{}_{}", emit_gnot_callee_expr(this_val), callee_text_bare)
                        } else {
                             callee_text_bare
                        };

                        let payload = if arg_parts.is_empty() {
                            format!("{callee_text}")
                        } else {
                            format!("{callee_text}({})", arg_parts.join(", "))
                        };

                        if let Some(target) = assign_to {
                            out.push_str(&format!("  {} <- {}, do({payload})\n", target, source_language));
                        } else {
                            out.push_str(&format!("  {}, do({payload})\n", source_language));
                        }
                    }
                }
                BridgeOperation::Return { plan } => {
                    if let BridgeNodePlan::Return { expression, .. } = plan {
                        out.push_str(&format!("  yield {}\n", emit_gnot_callee_expr(expression)));
                    }
                }
                BridgeOperation::Parallel { branches, .. } => {
                    for branch in branches {
                        if let BridgeNodePlan::Call { callee, args, assign_to, .. } = branch {
                            let mut arg_parts = Vec::new();
                            for a in args {
                                arg_parts.push(emit_gnot_callee_expr(a));
                            }
                            let payload = if arg_parts.is_empty() { emit_gnot_callee_expr(callee) } else { format!("{}({})", emit_gnot_callee_expr(callee), arg_parts.join(", ")) };
                            if let Some(target) = assign_to {
                                out.push_str(&format!("  {} <- {}, do({payload})\n", target, source_language));
                            } else {
                                out.push_str(&format!("  {}, do({payload})\n", source_language));
                            }
                        }
                    }
                }
            }
        }

        gnot::lint::apply_fixes(&out, gnot::lint::LintMode::Poetry)
    }
}

fn emit_gnot_callee_expr(expr: &BridgeExpression) -> String {
    match expr {
        BridgeExpression::Binding { name, .. } | BridgeExpression::Runtime { name, .. } => name.clone(),
        BridgeExpression::Input { .. } => "input_arg".to_string(),
        BridgeExpression::Member { target, property, .. } => format!("{}.{}", emit_gnot_callee_expr(target), property),
        _ => "_".to_string()
    }
}

impl PolyglotEmitter for LeanEmitter {
    fn emit(&self, operations: &[BridgeOperation], source_language: &str) -> String {
        let mut out = String::new();
        // Since Lean tactics are highly structural, we emit each top-level operation as a tactic.
        for op in operations {
            if source_language == "lean" {
                let ghost_mass = match op {
                    BridgeOperation::Assign { plan: BridgeNodePlan::Assign { ghost_mass, .. } } => ghost_mass,
                    BridgeOperation::Call { plan: BridgeNodePlan::Call { ghost_mass, .. } } => ghost_mass,
                    BridgeOperation::Return { plan: BridgeNodePlan::Return { ghost_mass, .. } } => ghost_mass,
                    _ => &None,
                };
                if let Some(s) = extract_ghost_source(ghost_mass) {
                    out.push_str(s);
                    out.push('\n');
                    continue;
                }
            }
            match op {
                BridgeOperation::Assign { plan } => {
                    if let BridgeNodePlan::Assign { binding_name, expression, .. } = plan {
                        // Lean does not use assignments in tactical mode, but we can emit a 'have' statement or 'let'.
                        out.push_str(&format!("  have {} := {}\n", binding_name, emit_expr_lean(expression, source_language)));
                    }
                }
                BridgeOperation::Call { plan } => {
                    if let BridgeNodePlan::Call { callee, args, assign_to, .. } = plan {
                        let mut call_str = String::new();
                        if let Some(target) = assign_to {
                            call_str.push_str(&format!("  have {} := ", target));
                        } else {
                            call_str.push_str("  ");
                        }
                        
                        let args_str: Vec<String> = args.iter().map(|a| emit_expr_lean(a, source_language)).collect();
                        
                        let callee_text = if let BridgeExpression::Member { property, .. } = callee {
                            property.clone()
                        } else {
                            emit_expr_lean(callee, source_language)
                        };
                        
                        if args_str.is_empty() {
                            call_str.push_str(&callee_text);
                        } else {
                            call_str.push_str(&format!("{} {}", callee_text, args_str.join(" ")));
                        }
                        out.push_str(&call_str);
                        out.push('\n');
                    }
                }
                BridgeOperation::Return { plan } => {
                    if let BridgeNodePlan::Return { expression, .. } = plan {
                        let expr_str = emit_expr_lean(expression, source_language);
                        if expr_str != "()" && expr_str != "None" {
                            out.push_str(&format!("  exact {}\n", expr_str));
                        }
                    }
                }
                BridgeOperation::Parallel { branches, .. } => {
                    // Parallel branches in Lean maps well to the `<;>` combinator
                    let mut b_out = String::new();
                    b_out.push_str("  ");
                    let mut b_vec = Vec::new();
                    for branch in branches {
                        if let BridgeNodePlan::Call { callee, args, .. } = branch {
                            let args_str: Vec<String> = args.iter().map(|a| emit_expr_lean(a, source_language)).collect();
                            let callee_text = if let BridgeExpression::Member { property, .. } = callee {
                                property.clone()
                            } else {
                                emit_expr_lean(callee, source_language)
                            };
                            if args_str.is_empty() {
                                b_vec.push(callee_text);
                            } else {
                                b_vec.push(format!("{} {}", callee_text, args_str.join(" ")));
                            }
                        }
                    }
                    b_out.push_str(&b_vec.join(" <;> "));
                    b_out.push('\n');
                    out.push_str(&b_out);
                }
            }
        }
        out
    }
}

fn emit_expr_lean(expr: &BridgeExpression, source_language: &str) -> String {
    if source_language == "lean" {
        let ghost_mass = match expr {
            BridgeExpression::Literal { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Binding { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Runtime { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Input { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Member { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Index { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Array { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Object { ghost_mass, .. } => ghost_mass,
        };
        if let Some(s) = extract_ghost_source(ghost_mass) {
            return s.to_string();
        }
    }
    match expr {
        BridgeExpression::Literal { value, .. } => {
            if value.is_null() {
                "()".to_string()
            } else if value.is_boolean() {
                if value.as_bool().unwrap() { "True".to_string() } else { "False".to_string() }
            } else {
                value.to_string()
            }
        }
        BridgeExpression::Binding { name, .. } | BridgeExpression::Runtime { name, .. } => {
            name.clone()
        }
        BridgeExpression::Input { .. } => "input_arg".to_string(),
        BridgeExpression::Member { target, property, .. } => {
            format!("{}.{}", emit_expr_lean(target, source_language), property)
        }
        BridgeExpression::Index { target, index, .. } => {
            format!("{} [{}]", emit_expr_lean(target, source_language), index)
        }
        BridgeExpression::Array { items, .. } => {
            // Arrays in Lean are often `#[]`
            let items_str: Vec<String> = items.iter().map(|i| emit_expr_lean(i, source_language)).collect();
            format!("#[{}]", items_str.join(", "))
        }
        BridgeExpression::Object { .. } => {
            "()".to_string()
        }
    }
}

impl PolyglotEmitter for FortranEmitter {
    fn emit(&self, operations: &[BridgeOperation], source_language: &str) -> String {
        let mut out = String::new();
        for op in operations {
            if source_language == "fortran" {
                let ghost_mass = match op {
                    BridgeOperation::Assign { plan: BridgeNodePlan::Assign { ghost_mass, .. } } => ghost_mass,
                    BridgeOperation::Call { plan: BridgeNodePlan::Call { ghost_mass, .. } } => ghost_mass,
                    BridgeOperation::Return { plan: BridgeNodePlan::Return { ghost_mass, .. } } => ghost_mass,
                    _ => &None,
                };
                if let Some(s) = extract_ghost_source(ghost_mass) {
                    out.push_str(s);
                    out.push('\n');
                    continue;
                }
            }
            match op {
                BridgeOperation::Assign { plan } => {
                    if let BridgeNodePlan::Assign { binding_name, expression, .. } = plan {
                        out.push_str(&format!("{} = {}\n", binding_name, emit_expr_fortran(expression, source_language)));
                    }
                }
                BridgeOperation::Call { plan } => {
                    if let BridgeNodePlan::Call { callee, args, assign_to, this_arg, .. } = plan {
                        let mut call_str = String::new();
                        if let Some(target) = assign_to {
                            call_str.push_str(&format!("{} = ", target));
                        } else {
                            call_str.push_str("CALL ");
                        }
                        
                        let args_str: Vec<String> = args.iter().map(|a| emit_expr_fortran(a, source_language)).collect();
                        
                        if let Some(this) = this_arg {
                            let callee_text = if let BridgeExpression::Member { property, .. } = callee {
                                property.clone()
                            } else {
                                emit_expr_fortran(callee, source_language)
                            };
                            call_str.push_str(&format!("{}%{}({})", emit_expr_fortran(this, source_language), callee_text, args_str.join(", ")));
                        } else {
                            call_str.push_str(&format!("{}({})", emit_expr_fortran(callee, source_language), args_str.join(", ")));
                        }
                        out.push_str(&call_str);
                        out.push('\n');
                    }
                }
                BridgeOperation::Return { plan } => {
                    if let BridgeNodePlan::Return { expression, .. } = plan {
                        let expr_str = emit_expr_fortran(expression, source_language);
                        if expr_str != "NULL()" {
                            out.push_str(&format!("RETURN {}\n", expr_str));
                        } else {
                            out.push_str("RETURN\n");
                        }
                    }
                }
                BridgeOperation::Parallel { branches, .. } => {
                    out.push_str("!$OMP PARALLEL SECTIONS\n");
                    for branch in branches {
                        out.push_str("!$OMP SECTION\n");
                        if let BridgeNodePlan::Call { callee, args, assign_to, .. } = branch {
                            let args_str: Vec<String> = args.iter().map(|a| emit_expr_fortran(a, source_language)).collect();
                            if let Some(target) = assign_to {
                                out.push_str(&format!("{} = {}({})\n", target, emit_expr_fortran(callee, source_language), args_str.join(", ")));
                            } else {
                                out.push_str(&format!("CALL {}({})\n", emit_expr_fortran(callee, source_language), args_str.join(", ")));
                            }
                        }
                    }
                    out.push_str("!$OMP END PARALLEL SECTIONS\n");
                }
            }
        }
        out
    }
}

fn emit_expr_fortran(expr: &BridgeExpression, source_language: &str) -> String {
    if source_language == "fortran" {
        let ghost_mass = match expr {
            BridgeExpression::Literal { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Binding { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Runtime { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Input { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Member { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Index { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Array { ghost_mass, .. } => ghost_mass,
            BridgeExpression::Object { ghost_mass, .. } => ghost_mass,
        };
        if let Some(s) = extract_ghost_source(ghost_mass) {
            return s.to_string();
        }
    }
    match expr {
        BridgeExpression::Literal { value, .. } => {
            if value.is_null() {
                "NULL()".to_string()
            } else if value.is_boolean() {
                if value.as_bool().unwrap() { ".TRUE.".to_string() } else { ".FALSE.".to_string() }
            } else if value.is_string() {
                format!("'{}'", value.as_str().unwrap())
            } else {
                value.to_string()
            }
        }
        BridgeExpression::Binding { name, .. } | BridgeExpression::Runtime { name, .. } => {
            name.clone()
        }
        BridgeExpression::Input { .. } => "input_arg".to_string(),
        BridgeExpression::Member { target, property, .. } => {
            format!("{}%{}", emit_expr_fortran(target, source_language), property)
        }
        BridgeExpression::Index { target, index, .. } => {
            format!("{}({})", emit_expr_fortran(target, source_language), index)
        }
        BridgeExpression::Array { items, .. } => {
            let items_str: Vec<String> = items.iter().map(|i| emit_expr_fortran(i, source_language)).collect();
            format!("(/ {} /)", items_str.join(", "))
        }
        BridgeExpression::Object { .. } => {
            "! Object mapping not natively supported in standard Fortran 90".to_string()
        }
    }
}

// Frankie Emitter Meta-Compiler
impl PolyglotEmitter for FrankieEmitter {
    fn emit(&self, operations: &[BridgeOperation], _source_language: &str) -> String {
        let mut out = String::new();
        out.push_str("// ═══════════════════════════════════════════════════════════════════════════\n");
        out.push_str("// FRANKENSTEIN COMPILED TOPOLOGY (Babelfish Meta-Polyglot Trace)\n");
        out.push_str("// ═══════════════════════════════════════════════════════════════════════════\n\n");
        
        let langs = ["c", "cpp", "csharp", "elixir", "fsharp", "go", "haskell",
        "java", "javascript", "kotlin", "lean", "lua", "ocaml",
        "php", "python", "ruby", "rust", "scala", "swift", "typescript", "zig"];

        let mut last_node = "source".to_string();
        out.push_str("(source: SourceFile { accept: 'any' })\n\n");

        for op in operations {
            match op {
                BridgeOperation::Assign { plan } => {
                    if let BridgeNodePlan::Assign { binding_name, expression, .. } = plan {
                        out.push_str(&format!("({binding_name}: VariableAssignment {{ val: '{}' }})\n", emit_expr_generic(expression, &LanguageSyntaxDialect::default()).replace("\"", "'")));
                        out.push_str(&format!("({last_node})-[:PROCESS]->({binding_name})\n\n"));
                        last_node = binding_name.clone();
                    }
                }
                BridgeOperation::Call { plan } => {
                    if let BridgeNodePlan::Call { callee, node_id, assign_to, .. } = plan {
                        let safe_node_id = node_id.replace("-", "_").replace(":", "_");
                        let callee_text = emit_expr_generic(callee, &LanguageSyntaxDialect::default());
                        let safe_callee = callee_text.replace("\"", "").replace("'", "");
                        
                        out.push_str(&format!("// Race function `{}` across all dialects\n", safe_callee));
                        let mut call_nodes = Vec::new();
                        for l in langs.iter() {
                            let node_name = format!("{}_{}", safe_node_id, l);
                            call_nodes.push(node_name.clone());
                            out.push_str(&format!("({node_name}: PolyglotBridgeCall {{ language: '{l}', fn: '{safe_callee}' }})\n"));
                        }
                        
                        let fork_str = call_nodes.join(" | ");
                        out.push_str(&format!("\n({last_node})-[:FORK]->({fork_str})\n"));
                        
                        let target_var = assign_to.clone().unwrap_or_else(|| format!("{}_result", safe_node_id));
                        out.push_str(&format!("({fork_str})-[:RACE {{ failure: 'vent' }}]->({target_var}: RaceResult)\n\n"));
                        last_node = target_var;
                    }
                }
                BridgeOperation::Return { plan } => {
                    if let BridgeNodePlan::Return { expression, .. } = plan {
                        let expr_str = emit_expr_generic(expression, &LanguageSyntaxDialect::default());
                        out.push_str(&format!("(terminal: ReturnNode {{ val: '{}' }})\n", expr_str.replace("\"", "'")));
                        out.push_str(&format!("({last_node})-[:FOLD]->(terminal)\n\n"));
                        last_node = "terminal".to_string();
                    }
                }
                BridgeOperation::Parallel { branches: _, .. } => {
                    out.push_str("// Frankie enforces massive parallel branches structurally! \n");
                }
            }
        }
        
        out
    }
}

impl PolyglotEmitter for ForrestEmitter {
    fn emit(&self, operations: &[BridgeOperation], _source_language: &str) -> String {
        let mut out = String::new();
        out.push_str("// ═══════════════════════════════════════════════════════════════════════════\n");
        out.push_str("// FORREST COMPILED TOPOLOGY (Recursive Convergent Polyglot Meta-Compiler)\n");
        out.push_str("// ═══════════════════════════════════════════════════════════════════════════\n\n");
        
        let langs = ["c", "cpp", "csharp", "elixir", "fsharp", "go", "haskell",
        "java", "javascript", "kotlin", "lean", "lua", "ocaml",
        "php", "python", "ruby", "rust", "scala", "swift", "typescript", "zig"];

        out.push_str("(generation: GenerationCounter { n: '0' })\n");
        out.push_str("(prev_winners: WinnerRecord { state: 'empty' })\n");
        out.push_str("(curr_winners: WinnerRecord { state: 'empty' })\n");
        out.push_str("(rejection_log: VoidBoundary { theorem: 'failure_strictly_more_informative' })\n\n");

        let mut last_node = "source".to_string();
        out.push_str("(source: SourceFile { accept: 'any', generation: 'n' })\n\n");

        for op in operations {
            match op {
                BridgeOperation::Assign { plan } => {
                    if let BridgeNodePlan::Assign { binding_name, expression, .. } = plan {
                        out.push_str(&format!("({binding_name}: VariableAssignment {{ val: '{}' }})\n", emit_expr_generic(expression, &LanguageSyntaxDialect::default()).replace("\"", "'")));
                        out.push_str(&format!("({last_node})-[:PROCESS]->({binding_name})\n\n"));
                        last_node = binding_name.clone();
                    }
                }
                BridgeOperation::Call { plan } => {
                    if let BridgeNodePlan::Call { callee, node_id, assign_to, .. } = plan {
                        let safe_node_id = node_id.replace("-", "_").replace(":", "_");
                        let callee_text = emit_expr_generic(callee, &LanguageSyntaxDialect::default());
                        let safe_callee = callee_text.replace("\"", "").replace("'", "");
                        
                        out.push_str(&format!("// Race function `{}` for convergence with Automagic Tests\n", safe_callee));
                        let mut call_nodes = Vec::new();
                        let mut verify_nodes = Vec::new();
                        
                        // Define the vented boundary first so we can route strict assertions failing directly into it
                        out.push_str(&format!("(vented_{safe_node_id}: VentedImplementations {{ info: 'N-1 bits per rejection' }})\n"));
                        
                        for l in langs.iter() {
                            let node_name = format!("{}_{}", safe_node_id, l);
                            let verify_name = format!("verify_{}", node_name);
                            call_nodes.push(node_name.clone());
                            verify_nodes.push(verify_name.clone());
                            
                            out.push_str(&format!("({node_name}: Implementation {{ language: '{l}', fn: '{safe_callee}' }})\n"));
                            out.push_str(&format!("({verify_name}: VerificationGate {{ source: 'automagic_fuzz', target: '{l}' }})\n"));
                            out.push_str(&format!("({node_name})-[:EXECUTE]->({verify_name})\n"));
                            
                            // Route test failure directly to the Vent
                            out.push_str(&format!("({verify_name})-[:ASSERT {{ pass: 'false' }}]->(vented_{safe_node_id})\n"));
                        }
                        
                        let launch_str = call_nodes.join(" | ");
                        let fork_str = verify_nodes.join(" | ");
                        out.push_str(&format!("\n({last_node})-[:FORK]->({launch_str})\n"));
                        
                        let target_var = assign_to.clone().unwrap_or_else(|| format!("{}_result", safe_node_id));
                        
                        // Only the nodes that pass the VerificationGate get to RACE!
                        out.push_str(&format!("({fork_str})-[:ASSERT {{ pass: 'true' }}]->(race_gate_{safe_node_id}: RaceGate)\n"));
                        out.push_str(&format!("(race_gate_{safe_node_id})-[:RACE {{ failure: 'vent' }}]->({target_var}: RaceResults {{ strategy: 'fastest_correct' }})\n"));
                        
                        out.push_str(&format!("// Failure Trilemma Chaos Bounds (gnosis-chaos Integration)\n"));
                        out.push_str(&format!("(chaos_{safe_node_id}: EnvironmentalChaos {{ trilemma_bounds: 'cache_starvation | network_jitter | core_saturation' }})\n"));
                        out.push_str(&format!("(chaos_{safe_node_id})-[:SATURATE]->({target_var})\n"));
                        
                        out.push_str(&format!("({target_var})-[:PROCESS]->(curr_winners)\n"));
                        
                        out.push_str(&format!("({target_var})-[:VENT]->(vented_{safe_node_id})\n"));
                        
                        out.push_str(&format!("// C0-C3 Metacognitive Feedback Loop (Using N-1 Rejection Bits as Generative Training Bounds)\n"));
                        out.push_str(&format!("(c0_heuristic_{safe_node_id}: FeedbackLoop {{ level: 'C0', state: 'syntax_coercion' }})\n"));
                        out.push_str(&format!("(c1_structural_{safe_node_id}: FeedbackLoop {{ level: 'C1', state: 'boundary_mutation' }})\n"));
                        out.push_str(&format!("(c2_semantic_{safe_node_id}: FeedbackLoop {{ level: 'C2', state: 'pointer_logic_repair' }})\n"));
                        out.push_str(&format!("(c3_architectural_{safe_node_id}: FeedbackLoop {{ level: 'C3', state: 'algorithmic_rewrite' }})\n"));
                        
                        out.push_str(&format!("(vented_{safe_node_id})-[:ANALYZE]->(c0_heuristic_{safe_node_id})\n"));
                        out.push_str(&format!("(c0_heuristic_{safe_node_id})-[:FAIL]->(c1_structural_{safe_node_id})\n"));
                        out.push_str(&format!("(c1_structural_{safe_node_id})-[:FAIL]->(c2_semantic_{safe_node_id})\n"));
                        out.push_str(&format!("(c2_semantic_{safe_node_id})-[:FAIL]->(c3_architectural_{safe_node_id})\n"));
                        out.push_str(&format!("(c3_architectural_{safe_node_id})-[:FAIL]->(rejection_log)\n"));
                        
                        // Mathematically bounce successes recursively back into the execution funnel
                        out.push_str(&format!("(c0_heuristic_{safe_node_id})-[:SUCCESS]->({launch_str})\n"));
                        out.push_str(&format!("(c1_structural_{safe_node_id})-[:SUCCESS]->({launch_str})\n"));
                        out.push_str(&format!("(c2_semantic_{safe_node_id})-[:SUCCESS]->({launch_str})\n"));
                        out.push_str(&format!("(c3_architectural_{safe_node_id})-[:SUCCESS]->({launch_str})\n\n"));
                        
                        last_node = target_var;
                    }
                }
                BridgeOperation::Return { plan } => {
                    if let BridgeNodePlan::Return { expression, .. } = plan {
                        let expr_str = emit_expr_generic(expression, &LanguageSyntaxDialect::default());
                        out.push_str(&format!("(terminal: ReturnNode {{ val: '{}' }})\n", expr_str.replace("\"", "'")));
                        out.push_str(&format!("({last_node})-[:PROCESS]->(terminal)\n\n"));
                        
                        out.push_str("// Convergence Inspection & Loop Back\n");
                        out.push_str("(convergence_check: ConvergenceCheck { theorem: 'void_walkers_converge' })\n");
                        out.push_str("(prev_winners)-[:FORK]->(convergence_check)\n");
                        out.push_str("(curr_winners)-[:FORK]->(convergence_check)\n");
                        out.push_str("(converged: Converged { regime: 'climax_community' })\n");
                        out.push_str("(not_converged: NotConverged { regime: 'succession' })\n");
                        out.push_str("(convergence_check)-[:FORK]->(converged | not_converged)\n\n");
                        
                        out.push_str("// Inspection Pipeline (User can Pause on NotConverged loops!)\n");
                        out.push_str("(inspection: InspectionGate { status: 'pausable', view: 'internal_state' })\n");
                        out.push_str("(shift_winners: ShiftState { op: 'curr_to_prev' })\n");
                        out.push_str("(not_converged)-[:PROCESS]->(inspection)\n");
                        out.push_str("(inspection)-[:PROCESS]->(shift_winners)\n");
                        out.push_str("(shift_winners)-[:PROCESS]->(prev_winners)\n");
                        out.push_str("(increment: IncrementGeneration)\n");
                        out.push_str("(shift_winners)-[:PROCESS]->(increment)\n");
                        out.push_str("(increment)-[:PROCESS]->(generation)\n");
                        out.push_str("(compose_winners: ComposeWinners { strategy: 'best_per_function' })\n");
                        out.push_str("(curr_winners)-[:PROCESS]->(compose_winners)\n");
                        out.push_str("(compose_winners)-[:PROCESS]->(source)\n\n");
                        
                        out.push_str("// Output Pipeline when Converged\n");
                        out.push_str("(optimal_mix: OptimalMix { theorem: 'diversity_optimality_master' })\n");
                        out.push_str("(converged)-[:PROCESS]->(optimal_mix)\n");
                        out.push_str("(emit_compiler: EmitCompiler { format: 'polyglot_gg' })\n");
                        out.push_str("(optimal_mix)-[:PROCESS]->(emit_compiler)\n");
                        out.push_str("(terminal)-[:FOLD]->(emit_compiler)\n");
                        
                        last_node = "emit_compiler".to_string();
                    }
                }
                BridgeOperation::Parallel { branches: _, .. } => {}
            }
        }
        out
    }
}
